queries.sparql:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
SELECT ?city ?coord WHERE {
  { SELECT ?fka WHERE { ?f a :Flights ; p:ForeignKey_Airline ?fka } GROUP BY ?fka ORDER BY DESC(COUNT(*)) LIMIT 1 }
  ?al a :Airlines ; p:Airlines_Id ?fka .
  ?f2 a :Flights ; p:ForeignKey_Airline ?fka ; p:IATA_Departure ?dep .
  ?ap a :Airports ; p:IATA_Code ?dep ; p:City ?city ; p:Coordinates ?coord .
}

